    if arg:match("[%z%c|;&$`\\\"'%(%)%{%}%[%]<>!#~%*%?%%]") then
        return nil, "argument contains forbidden characters"
    end
    -- Reject arguments starting with dash to prevent option injection
    -- (unless specifically allowed per command)
    if arg:match("^%-") then
        return nil, "arguments starting with '-' are not allowed"
    end
    -- Only allow alphanumeric, dots, underscores, hyphens (non-leading), slashes, colons, equals, spaces
    if not arg:match("^[%w%.%_%-%/:%=% ]+$") then
        return nil, "argument contains disallowed characters"
    end
    return arg, nil
end

