-- Shell-escape a single argument for use in os.execute (POSIX sh)
-- We use this ONLY with validated arguments as a defense-in-depth measure
local function shell_quote(s)
    -- Replace every single quote with '\'' and wrap in single quotes
    return "'" .. s:gsub("'", "'\\''") .. "'"
end

-- Build a safe command string from a fixed executable and validated argument array
local function build_command_string(exec_path, args)
    local parts = {shell_quote(exec_path)}
    for _, arg in ipairs(args) do
        parts[#parts + 1] = shell_quote(arg)
    end
    -- Redirect stderr to stdout for capture
    return table.concat(parts, " ") .. " 2>&1"
end

-- Execute command and capture output using io.popen (since os.execute doesn't capture output)
-- We avoid os.execute because we need to return output to the HTTP client
local function execute_command(exec_path, args)
    local cmd_string = build_command_string(exec_path, args)

    local handle, err = io.popen(cmd_string, "r")
    if not handle then
        return nil, "failed to execute command: " .. (err or "unknown error")
    end

    local output = handle:read("*a")
    local ok, exit_type, exit_code = handle:close()

    return {
        output = output or "",
        success = (exit_type == "exit" and exit_code == 0),
        exit_code = exit_code or -1
    }
end

-- Rate limiting using shared dictionary
local function check_rate_limit(remote_addr)
    local limit_dict = ngx.shared.cmd_rate_limit
    if not limit_dict then
        -- If shared dict not configured, allow but log warning
        ngx.log(ngx.WARN, "cmd_rate_limit shared dict not configured, skipping rate limit")
        return true
    end

    local key = "rate:" .. remote_addr
    local count, err = limit_dict:incr(key, 1, 0, 60) -- 60 second window
    if not count then
        ngx.log(ngx.ERR, "rate limit incr failed: ", err)
        return true -- fail open
    end

    -- Allow max 10 requests per minute per IP
    if count > 10 then
        return false
    end
    return true
end

